我来帮你写一个健壮的 JavaScript `debounce` 函数，包含多种常见用法。

## 基础版 debounce

```javascript
/**
 * 创建一个防抖函数
 * @param {Function} fn - 要执行的函数
 * @param {number} delay - 延迟时间（毫秒）
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay) {
  let timer = null;

  return function (...args) {
    const context = this;

    // 清除之前的定时器
    if (timer) clearTimeout(timer);

    // 设置新的定时器
    timer = setTimeout(() => {
      fn.apply(context, args);
      timer = null;
    }, delay);
  };
}
```

## 带立即执行选项（leading + trailing）

```javascript
/**
 * 防抖函数，支持 leading 和 trailing
 * @param {Function} fn - 目标函数
 * @param {number} delay - 延迟毫秒数
 * @param {Object} [options]
 * @param {boolean} [options.leading=false] - 是否在延迟开始前立即执行一次
 * @param {boolean} [options.trailing=true] - 是否在延迟结束后执行
 * @param {number} [options.maxWait] - 最大等待时间（保证至少执行一次）
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true, maxWait } = options;

  let timer = null;
  let lastArgs = null;
  let lastContext = null;
  let lastCallTime = null;
  let lastInvokeTime = 0;

  function invoke() {
    lastInvokeTime = Date.now();
    fn.apply(lastContext, lastArgs);
    lastArgs = lastContext = null;
  }

  function startTimer(remainingWait) {
    timer = setTimeout(() => {
      timer = null;
      if (trailing && lastArgs) {
        invoke();
      }
    }, remainingWait);
  }

  function trailingEdge() {
    timer = null;
    if (trailing && lastArgs) {
      invoke();
    }
  }

  function leadingEdge() {
    lastInvokeTime = Date.now();
    if (leading) {
      invoke();
    }
    startTimer(delay);
  }

  function debounced(...args) {
    const now = Date.now();
    const isFirstCall = lastCallTime === null;

    lastCallTime = now;
    lastArgs = args;
    lastContext = this;

    if (isFirstCall) {
      if (leading) {
        leadingEdge();
      } else {
        startTimer(delay);
      }
    } else {
      // 清除旧定时器
      if (timer) clearTimeout(timer);

      // 检查 maxWait
      if (maxWait && (now - lastInvokeTime) >= maxWait) {
        trailingEdge();
        leadingEdge();
      } else {
        startTimer(delay);
      }
    }
  }

  // 取消防抖
  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = lastContext = null;
    lastCallTime = null;
    lastInvokeTime = 0;
  };

  // 立即执行
  debounced.flush = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    if (lastArgs) {
      invoke();
    }
  };

  return debounced;
}
```

## 使用示例

```javascript
// 1. 搜索输入框防抖（最常用）
const searchInput = document.getElementById('search');
const handleSearch = debounce((event) => {
  console.log('搜索:', event.target.value);
  // 调用 API
}, 300);

searchInput.addEventListener('input', handleSearch);

// 2. 窗口 resize 防抖
const handleResize = debounce(() => {
  console.log('窗口大小:', window.innerWidth, 'x', window.innerHeight);
}, 200);

window.addEventListener('resize', handleResize);

// 3. 按钮防抖（防止重复提交）
const submitBtn = document.getElementById('submit');
const handleSubmit = debounce(
  () => { console.log('提交表单'); },
  1000,
  { leading: true, trailing: false }  // 立即执行，不延迟
);
submitBtn.addEventListener('click', handleSubmit);

// 4. 保证至少执行一次（maxWait）
const handleScroll = debounce(
  () => { console.log('滚动结束'); },
  500,
  { maxWait: 1000 }  // 最多等 1 秒，保证执行
);
window.addEventListener('scroll', handleScroll);

// 5. 取消和立即执行
const debouncedFn = debounce(() => console.log('执行'), 1000);
debouncedFn();
debouncedFn.cancel();       // 取消未执行的调用
debouncedFn.flush();        // 立即执行
```

## 一行版（面试常见）

```javascript
const debounce = (fn, delay) => {
  let t;
  return (...args) => (clearTimeout(t), t = setTimeout(() => fn(...args), delay));
};
```

## 核心要点

| 特性 | 说明 |
|------|------|
| **延迟执行** | 连续触发时只执行最后一次 |
| **leading** | 第一次立即执行，后续等待 |
| **trailing** | 停止触发后执行（默认） |
| **maxWait** | 最大等待时间，保证至少执行一次 |
| **cancel()** | 取消未执行的调用 |
| **flush()** | 立即执行并清空 |

